## Clara Tool - Buscar Contato v2

Busca contato + oportunidade no GHL por telefone.

**Input:** { phone }
**Output:** { encontrado, contact_id, nome, telefone, email, tags, empresa, oportunidade_id, etapa_atual }

parameters.jsCode:
// Validate input + unwrap $fromAI query fields
// n8n LangChain toolWorkflow puts $fromAI fields inside "query" object
// while static expressions stay at top level
const raw = $input.first().json;

// Merge query fields into top level
const query = raw.query || {};
const input = { ...raw };

// Unwrap query fields (AI-generated via $fromAI)
if (typeof query === 'object' && query !== null) {
  for (const [key, value] of Object.entries(query)) {
    if (key !== 'phone' && input[key] === undefined) {
      input[key] = value;
    }
  }
}
delete input.query;

// Validate phone
const phone = input.phone || '';
if (!phone || phone.trim() === '') {
  return [{ json: { resultado: 'Erro: telefone do lead não fornecido.', sucesso: false } }];
}

// Clean phone (remove non-digits, keep +)
input.phone = phone.replace(/[^\d+]/g, '');

return [{ json: input }];

// Format response for AI agent
const contact = $('GHL Buscar Contato').item.json.contact || null;
const opps = $('GHL Buscar Oportunidade').item.json.opportunities || [];

if (!contact) {
  return [{ json: {
    resultado: "Contato não encontrado no GHL para este número.",
    encontrado: false
  }}];
}

const opp = opps.length > 0 ? opps[0] : null;

return [{ json: {
  resultado: "Contato encontrado no GHL.",
  encontrado: true,
  contact_id: contact.id,
  nome: contact.firstName + (contact.lastName ? ' ' + contact.lastName : ''),
  telefone: contact.phone,
  email: contact.email || '',
  tags: (contact.tags || []).join(', '),
  empresa: contact.companyName || '',
  oportunidade_id: opp ? opp.id : '',
  etapa_atual: opp ? opp.pipelineStageId : '',
  status_oportunidade: opp ? opp.status : '',
  campos_personalizados: JSON.stringify(contact.customFields || [])
}}];

